let currentFilter = 'todos';

function getIniciales(nombre) {
  return nombre.split(' ').map(n => n[0]).join('').substring(0,2);
}

function getCountClass(count) {
  if (count > 10) return 'count-high';
  if (count >= 5) return 'count-medium';
  return 'count-low';
}

function renderContent() {
  const contentArea = document.getElementById('contentArea');
  contentArea.innerHTML = '';

  let totalEst = 0, totalPen = 0, totalGrup = 0, criticos = 0;

  for (const [grupo, estudiantes] of Object.entries(data)) {
    totalGrup++;

    const grupoSection = document.createElement('div');
    grupoSection.className = 'group-section';
    grupoSection.dataset.grupo = grupo;

    const estudiantesFiltrados = [];
    for (const [nombre, pendientes] of Object.entries(estudiantes)) {
      const count = pendientes.length;
      totalEst++;
      totalPen += count;
      if (count > 10) criticos++;

      let mostrar = true;
      if (currentFilter === 'criticos' && count <= 10) mostrar = false;
      if (currentFilter === 'moderados' && (count < 5 || count > 10)) mostrar = false;
      if (currentFilter === 'leves' && count >= 5) mostrar = false;

      const searchTerm = document.getElementById('searchBox').value.toLowerCase();
      if (searchTerm && !nombre.toLowerCase().includes(searchTerm)) mostrar = false;

      if (mostrar) estudiantesFiltrados.push({nombre, pendientes, count});
    }

    if (estudiantesFiltrados.length === 0) continue;

    grupoSection.innerHTML = `
      <div class="group-header" onclick="toggleGrupo(this)">
        <h2>👥 ${grupo} <span class="badge">${estudiantesFiltrados.length} estudiantes</span></h2>
        <span class="toggle-icon">▼</span>
      </div>
      <div class="group-content">
        ${estudiantesFiltrados.map(e => `
          <div class="student-card" data-count="${e.count}">
            <div class="student-header" onclick="toggleEstudiante(event, this)">
              <div class="student-name">
                <div class="avatar">${getIniciales(e.nombre)}</div>
                ${e.nombre}
              </div>
              <div class="pendientes-count">
                <span class="count-badge ${getCountClass(e.count)}">${e.count} cuestionarios</span>
              </div>
            </div>
            <div class="student-pendientes">
              ${e.pendientes.map(p => `
                <div class="pendiente-item">
                  <span class="pendiente-icon">📝</span>
                  <span class="pendiente-text">${p}</span>
                </div>
              `).join('')}
            </div>
          </div>
        `).join('')}
      </div>
    `;

    contentArea.appendChild(grupoSection);
  }

  document.getElementById('totalEstudiantes').textContent = totalEst;
  document.getElementById('totalPendientes').textContent = totalPen;
  document.getElementById('totalGrupos').textContent = totalGrup;
  document.getElementById('promedioPendientes').textContent = totalEst > 0 ? (totalPen/totalEst).toFixed(1) : 0;
  document.getElementById('criticosCount').textContent = criticos;
  
}

function toggleGrupo(header) {
  header.classList.toggle('collapsed');
  const content = header.nextElementSibling;
  content.classList.toggle('collapsed');
  
}

function toggleEstudiante(event, header) {
  event.stopPropagation();
  const pendientes = header.nextElementSibling;
  pendientes.classList.toggle('expanded');
  
}

function filtrarTodos() { currentFilter = 'todos'; updateFilterButtons(); renderContent(); actualizarUltimaActualizacion();}
function filtrarCriticos() { currentFilter = 'criticos'; updateFilterButtons(); renderContent(); actualizarUltimaActualizacion(); }
function filtrarModerados() { currentFilter = 'moderados'; updateFilterButtons(); renderContent(); actualizarUltimaActualizacion(); }
function filtrarLeves() { currentFilter = 'leves'; updateFilterButtons(); renderContent(); actualizarUltimaActualizacion(); }

function updateFilterButtons() {
  document.querySelectorAll('.btn-filter').forEach(btn => btn.classList.remove('active'));
  const buttons = document.querySelectorAll('.btn-filter');
  if (currentFilter === 'todos') buttons[0].classList.add('active');
  if (currentFilter === 'criticos') buttons[1].classList.add('active');
  if (currentFilter === 'moderados') buttons[2].classList.add('active');
  if (currentFilter === 'leves') buttons[3].classList.add('active');
}

function buscarEstudiante() {
  renderContent();
  actualizarUltimaActualizacion();
}

function expandirTodos() {
  document.querySelectorAll('.student-pendientes').forEach(el => el.classList.add('expanded'));
  document.querySelectorAll('.group-content').forEach(el => el.classList.remove('collapsed'));
  document.querySelectorAll('.group-header').forEach(el => el.classList.remove('collapsed'));
  actualizarUltimaActualizacion();
}

function colapsarTodos() {
  document.querySelectorAll('.student-pendientes').forEach(el => el.classList.remove('expanded'));
  document.querySelectorAll('.group-content').forEach(el => el.classList.add('collapsed'));
  document.querySelectorAll('.group-header').forEach(el => el.classList.add('collapsed'));
  actualizarUltimaActualizacion();
}

function exportarExcel() {

    const wb = XLSX.utils.book_new();

    Object.entries(data).forEach(([grupo, estudiantes]) => {

        const wsData = [];

        wsData.push([
            "Estudiante",
            "Cantidad de Pendientes",
            "Cuestionarios Pendientes"
        ]);

        Object.entries(estudiantes)
            .sort((a,b) => b[1].length - a[1].length)
            .forEach(([nombre, pendientes]) => {

                const listaOrdenada = pendientes
                    .map((p,index) => `${index + 1}. ${p}`)
                    .join("\n");

                wsData.push([
                    nombre,
                    pendientes.length,
                    listaOrdenada
                ]);
            });

        const ws = XLSX.utils.aoa_to_sheet(wsData);

        ws['!cols'] = [
            { wch: 35 },
            { wch: 18 },
            { wch: 90 }
        ];

        for(let row = 1; row <= wsData.length; row++){
            ws[`C${row}`] && (ws[`C${row}`].s = {
                alignment:{
                    wrapText:true,
                    vertical:"top"
                }
            });
        }

        const range = XLSX.utils.decode_range(ws['!ref']);

        for(let C = range.s.c; C <= range.e.c; C++){

            const cell = XLSX.utils.encode_cell({r:0,c:C});

            if(!ws[cell]) continue;

            ws[cell].s = {
                fill:{
                    fgColor:{rgb:"2563EB"}
                },
                font:{
                    color:{rgb:"FFFFFF"},
                    bold:true,
                    sz:12
                },
                alignment:{
                    horizontal:"center",
                    vertical:"center"
                },
                border:{
                    top:{style:"thin"},
                    bottom:{style:"thin"},
                    left:{style:"thin"},
                    right:{style:"thin"}
                }
            };
        }

        for(let R = 1; R <= range.e.r; R++){

            const total = ws[`B${R+1}`];

            let color = "DCFCE7";

            if(total){
                if(total.v > 10) color = "FEE2E2";
                else if(total.v >= 5) color = "FEF3C7";
            }

            for(let C = 0; C <= range.e.c; C++){

                const cell = XLSX.utils.encode_cell({r:R,c:C});

                if(!ws[cell]) continue;

                ws[cell].s = {
                    fill:{
                        fgColor:{rgb:color}
                    },
                    alignment:{
                        wrapText:true,
                        vertical:"top"
                    },
                    border:{
                        top:{style:"thin", color:{rgb:"D1D5DB"}},
                        bottom:{style:"thin", color:{rgb:"D1D5DB"}},
                        left:{style:"thin", color:{rgb:"D1D5DB"}},
                        right:{style:"thin", color:{rgb:"D1D5DB"}}
                    }
                };
            }
        }

        ws['!freeze'] = {
            xSplit:0,
            ySplit:1
        };

        XLSX.utils.book_append_sheet(
            wb,
            ws,
            grupo.substring(0,31)
        );

    });

    XLSX.writeFile(
        wb,
        `Reporte_Cuestionarios_${new Date().toISOString().split('T')[0]}.xlsx`
    );
    actualizarUltimaActualizacion();
}
actualizarUltimaActualizacion();
renderContent();



function actualizarUltimaActualizacion() {
  const fecha = new Date();

  const opciones = {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit'
  };

  document.getElementById('ultimaActualizacion').textContent =
    "Última actualización: " + fecha.toLocaleDateString('es-NI', opciones);
}

